def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf if item != 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        factor = 1.0
        penalty = 0.0
        bonus = 0.0
        decay = 1.0
        extra = 0.0
        if item == 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 8):
                penalty += ((-1) ** k) * (ratio ** (2 * k)) / (k ** 2 + 2)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j + 1.5))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x)
                score += sign * (ratio ** x) / (x + 1.5)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2.5))
            score = abs(score) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 6)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 30 if ratio < 2.3 else 20 if ratio < 2.7 else 12
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 7):
                    extra += (ratio ** m) / (m + 4)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for n in range(1, 18):
                if n % 5 == 0:
                    temp_score += (ratio ** n) / (n * 2)
                elif n % 3 == 0:
                    temp_score -= (ratio ** n) / (n * 4)
                else:
                    temp_score += (ratio ** n) / (n * 3)
            if ratio < 1.25:
                multiplier = 40
            elif ratio < 1.5:
                multiplier = 30
            elif ratio < 1.75:
                multiplier = 20
            else:
                multiplier = 15
            score = abs(temp_score) * multiplier
            if 1.85 < ratio < 2:
                extra = 0
                for q in range(1, 10):
                    extra += (ratio ** q) / (q + 2)
                score += extra * 2
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_val = 0
            for r in range(1, 20):
                if r % 6 == 0:
                    temp_val += (ratio ** r) / (r * 2)
                elif r % 4 == 0:
                    temp_val -= (ratio ** r) / (r * 5)
                elif r % 3 == 0:
                    temp_val += (ratio ** r) / (r * 7)
                else:
                    temp_val -= (ratio ** r) / (r * 4)
            if ratio < 0.1:
                multiplier = 50
            elif ratio < 0.3:
                multiplier = 35
            elif ratio < 0.5:
                multiplier = 25
            elif ratio < 0.7:
                multiplier = 12
            else:
                multiplier = 9
            score = abs(temp_val) * multiplier
            if ratio > 0.9:
                extra_penalty = 0
                for s in range(1, 10):
                    extra_penalty += (ratio ** s) / (s + 2)
                score += extra_penalty * 3
            priorities[i] = score
        else:
            priorities[i] = np.inf
        for z in range(1, 5):
            factor *= (1 + z / (capacity + z))
        priorities[i] *= factor
        if priorities[i] < 0 or np.isnan(priorities[i]) or np.isinf(priorities[i]):
            priorities[i] = np.inf
    return priorities
